  "title": "स्केलिंग व्यवहार",
  "group": "ऑरोरा सर्वरलेस",
  "options": [
    {
      "text": "स्केलिंग गति वर्तमान और कॉन्फ़िगर की गई क्षमता पर निर्भर करती है"
    },
    {
      "text": "आवश्यकता पर तुरंत स्केल करता है"
    },
    {
      "text": "केवल निर्धारित अंतराल पर स्केल करता है"
    },
    {
      "text": "केवल मैनुअल स्केलिंग"
    }
  ],
  "questionProse": [
    "अचानक ट्रैफ़िक स्पाइक्स को संभालने के लिए Aurora Serverless पर निर्भर करते समय मुख्य विचार क्या है?"
  ],
  "explanationProse": [
    "ऑरोरा सर्वरलेस स्केलिंग:\n      - ऑरोरा सर्वरलेस v2 क्षमता को सूक्ष्म ACU वृद्धि में स्केल करता है\n      - स्केलिंग गति वर्तमान क्षमता और न्यूनतम/अधिकतम ACU सेटिंग्स पर निर्भर करती है\n      - समर्थित संस्करणों को कॉन्फ़िगर करने पर 0 ACU पर ऑटो‑पॉज़ किया जा सकता है\n      - बिलिंग ACU के आधार पर प्रति सेकंड होती है\n\n      सर्वोत्तम प्रथाएँ:\n      - महत्वपूर्ण कार्यभार पर अचानक स्पाइक्स को संभालने के लिए न्यूनतम क्षमता को पर्याप्त उच्च रखें\n      - स्केलिंग घटनाओं की निगरानी करें\n      - कनेक्शन प्रबंधन को ध्यान में रखें"
  ]
